+        }
+        if text_lower.contains("crater") || text_lower.contains("hole") {
+            embed[1] = 100;
+        }
+        if text_lower.contains("slope") || text_lower.contains("incline") {
+            embed[2] = 100;
+        }
+
+        // Anomaly/danger keywords
