+        results.sort_by_key(|(_, d)| *d);
+
+        let mut top_k: HVec<(usize, i32), 8> = HVec::new();
+        for (idx, dist) in results.iter().take(k) {
+            // Increment use count
+            if let Some(knowledge) = self.knowledge.get_mut(*idx) {
+                knowledge.use_count += 1;
+            }
+            let _ = top_k.push((*idx, *dist));
+        }
+
+        top_k
+    }
