+            let config = ModelConfig::for_variant(variant);
+            assert!(config.validate(variant).is_ok());
+
+            let size = config.estimate_size();
+            println!("{:?}: {} bytes ({:.1} KB)", variant, size, size as f32 / 1024.0);
+        }
+    }
