+    }
+}
+
+/// Test rotary embeddings
+#[test]
+fn test_rotary_embeddings() {
+    let mut rope = RotaryEmbedding::new(32, 10000);
+
+    // Test different positions
+    for pos in [0, 5, 10, 20] {
